function GamePacketSender:sendBedWarRewardResult(rakssid, rewardIds)
    if rewardIds == "" then
        return
    end
    local player = PlayerManager:getPlayerByRakssid(rakssid)
    if not player then
        return
    end
    local params = {
        rewardIds = rewardIds
    }

    local data = DataBuilder.new():fromTable(params):getData()
    PacketSender:sendLuaCommonData(rakssid, "RewardResult", data)
end

